import OpenAI from "openai";

const client = new OpenAI();

const model = process.env.MODEL || "gpt-4o";
const systemPrompt = process.env.SYSTEM_PROMPT || "You are a helpful assistant.";
const userMessage = process.env.USER_MESSAGE || "Hello!";
const temperature = parseFloat(process.env.TEMPERATURE || "1");

const stream = await client.chat.completions.create({
  model,
  messages: [
    { role: "system", content: systemPrompt },
    { role: "user", content: userMessage },
  ],
  temperature,
  stream: true,
  stream_options: { include_usage: true },
});

const chunks = [];
let usage = null;

for await (const chunk of stream) {
  const content = chunk.choices[0]?.delta?.content || "";
  if (content) {
    chunks.push(content);
    process.stdout.write(content);
  }
  if (chunk.usage) {
    usage = chunk.usage;
  }
}

console.log();
if (usage) {
  console.error(JSON.stringify({
    usage: {
      promptTokens: usage.prompt_tokens,
      completionTokens: usage.completion_tokens,
      totalTokens: usage.total_tokens,
    },
  }));
}

curl -N -s https://api.openai.com/v1/chat/completions \
  -H "Content-Type: application/json" \
  -H "Authorization: Bearer $OPENAI_API_KEY" \
  -d "{
    \"model\": \"${MODEL:-gpt-4o}\",
    \"messages\": [
      {\"role\": \"system\", \"content\": \"${SYSTEM_PROMPT:-You are a helpful assistant.}\"},
      {\"role\": \"user\", \"content\": \"${USER_MESSAGE:-Hello!}\"}
    ],
    \"stream\": true
  }"
